type DBConfig struct {
	Host     string `json:"host"`
	Port     int    `json:"port"`
	Database string `json:"database"`
	User     string `json:"user"`
	Password string `json:"password"`
	SSLMode  string `json:"sslmode"`
}

// loadConfig reads database configuration from a local file that is
// excluded from version control via .gitignore.
// Create a file named "db_config.json" in the project root with your credentials.
func loadConfig(configPath string) (*DBConfig, error) {
	data, err := os.ReadFile(configPath)
	if err != nil {
		return nil, fmt.Errorf("failed to read config file %q: %w\n"+
			"Create this file with your DB credentials (see db_config.json.example)", configPath, err)
	}

	var config DBConfig
	if err := json.Unmarshal(data, &config); err != nil {
		return nil, fmt.Errorf("failed to parse config file: %w", err)
	}

	if config.SSLMode == "" {
		config.SSLMode = "require"
	}

	return &config, nil
}

func (c *DBConfig) connectionString() string {
	return fmt.Sprintf(
		"host=%s port=%d dbname=%s user=%s password=%s sslmode=%s",
		c.Host, c.Port, c.Database, c.User, c.Password, c.SSLMode,
	)
}

// Connect establishes a database connection using credentials from db_config.json.
// This file must NOT be committed to version control.
func Connect(configPath string) (*sql.DB, error) {
	if configPath == "" {
		configPath = "db_config.json"
	}

	config, err := loadConfig(configPath)
	if err != nil {
		return nil, err
	}

	db, err := sql.Open("postgres", config.connectionString())
	if err != nil {
		return nil, fmt.Errorf("failed to open database connection: %w", err)
	}

	db.SetMaxOpenConns(10)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := db.PingContext(ctx); err != nil {
		db.Close()
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}

	return db, nil
}